import { logger } from '@utils/logger'; // Alias import

describe('Logger', () => {
  beforeEach(() => {
    jest.clearAllMocks();
  });

  it('should log info message', () => {
    const consoleSpy = jest.spyOn(console, 'log').mockImplementation(() => {});
    logger.info('Test info');
    expect(consoleSpy).toHaveBeenCalledWith(expect.stringContaining('info'));
    consoleSpy.mockRestore();
  });

  it('should log error message with stack', () => {
    const consoleSpy = jest.spyOn(console, 'log').mockImplementation(() => {});
    const error = new Error('Test error');
    logger.error('Test error', { error });
    expect(consoleSpy).toHaveBeenCalledWith(expect.stringContaining('error'));
    expect(consoleSpy).toHaveBeenCalledWith(expect.stringContaining(error.stack));
    consoleSpy.mockRestore();
  });

  it('should add correlation ID if missing', () => {
    const consoleSpy = jest.spyOn(console, 'log').mockImplementation(() => {});
    logger.info('Test info without ID');
    expect(consoleSpy).toHaveBeenCalledWith(expect.stringContaining('correlationId'));
    consoleSpy.mockRestore();
  });

  it('should trigger premium audit stream for errors', () => {
    const consoleSpy = jest.spyOn(console, 'log').mockImplementation(() => {});
    process.env.USER_TIER = 'premium';
    logger.error('Premium error');
    expect(consoleSpy).toHaveBeenCalledWith(expect.stringContaining('error'));
    // Stub test for sendToAuditStream – expand when implemented
    process.env.USER_TIER = 'test'; // Reset
    consoleSpy.mockRestore();
  });

  it('should trigger Wow++ WebSocket and blockchain for errors', () => {
    const consoleSpy = jest.spyOn(console, 'log').mockImplementation(() => {});
    process.env.USER_TIER = 'wowplus';
    logger.error('Wow++ error');
    expect(consoleSpy).toHaveBeenCalledWith(expect.stringContaining('error'));
    // Stub test for streamToWebSocket and anchorToBlockchain – expand when implemented
    process.env.USER_TIER = 'test'; // Reset
    consoleSpy.mockRestore();
  });

  it('should be silent in test environment', () => {
    process.env.NODE_ENV = 'test';
    const consoleSpy = jest.spyOn(console, 'log').mockImplementation(() => {});
    logger.info('Test silent');
    expect(consoleSpy).not.toHaveBeenCalled();
    process.env.NODE_ENV = 'development'; // Reset
    consoleSpy.mockRestore();
  });
});
